import { useState } from "react";

import Counter from "./Counter";
import Stopwatch from "./Stopwatch";
import CrystalBall from "./CrystalBall";
import DuckHunt from "./DuckHunt";
import PizzaBuilder from "./PizzaBuilder";
import TicTacToe from "./TicTacToe";
import TodoApp from "./TodoApp";

const apps = [
  {
    name: "Counter",
    icon: "🔢",
    component: <Counter />,
  },
  {
    name: "Stopwatch",
    icon: "⏱️",
    component: <Stopwatch />,
  },
  {
    name: "Crystal Ball",
    icon: "🔮",
    component: <CrystalBall />,
  },
  {
    name: "Duck Hunt",
    icon: "🦆",
    component: <DuckHunt />,
  },
  {
    name: "Pizza Builder",
    icon: "🍕",
    component: <PizzaBuilder />,
  },
  {
    name: "Tic Tac Toe",
    icon: "⭕",
    component: <TicTacToe />,
  },
  {
    name: "Todo",
    icon: "📝",
    component: <TodoApp />,
  },
];

export default function App() {
  const [dark, setDark] = useState(false);
  const [selected, setSelected] = useState(null);

  return (
    <div className={dark ? "dark" : ""}>
      <button
        style={{
          position: "fixed",
          top: 20,
          right: 20,
        }}
        onClick={() => setDark(!dark)}
      >
        {dark ? "☀️" : "🌙"}
      </button>

      {selected ? (
        <>
          <button onClick={() => setSelected(null)}>
            ← Back
          </button>

          {selected.component}
        </>
      ) : (
        <div className="container">
          <h1>⚛️ React Mini Apps</h1>

          <p>
            Small apps built with React
          </p>

          <section>
            {apps.map(app => (
              <button
                key={app.name}
                onClick={() => setSelected(app)}
              >
                {app.icon} {app.name}
              </button>
            ))}
          </section>
        </div>
      )}
    </div>
  );
}
